private fun triggerSuccessiveLoop() {
    val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
    val useSensors = prefs.getBoolean("sensor_assisted", false)

    if (successiveRemaining > 0) {
        if (!isCapturingBatch) {
            isCapturingBatch = true
            batchStartTime = System.currentTimeMillis()
            if (useSensors) {
                sensorManager?.registerListener(this, accelSensor, SensorManager.SENSOR_DELAY_UI)
                sensorManager?.registerListener(this, gravitySensor, SensorManager.SENSOR_DELAY_UI)
                hapticHandler.post(hapticTickRunnable)
                DebugLogger.log("SENSOR", "Batch started: Sensors engaged")
            }
        }

        val waitStartTime = System.currentTimeMillis()

        // Decision Loop
        val checkCondition = object : Runnable {
            override fun run() {
                if (!isCapturingBatch) return

                val elapsed = System.currentTimeMillis() - waitStartTime
                val isTilted = tiltAngle > 25.0f // Threshold for "Wall Check"
                val isMoving = movementMagnitude > 0.4f
                val timedOut = elapsed > 5000L

                when {
                    isTilted && !timedOut -> {
                        // Double Thump for tilt (distinct from movement ticks)
                        if (elapsed % 1500 < 50) {
                            DebugLogger.log("SENSOR", "Tilt alert: ${tiltAngle}deg")
                            hapticPulse(40, 40)
                            handler.postDelayed({ hapticPulse(40, 40) }, 100)
                        }
                        handler.postDelayed(this, 200)
                    }
                    isMoving && !timedOut -> {
                        // Just wait for stability, hapticTickRunnable handles the Geiger clicks
                        handler.postDelayed(this, 100)
                    }
                    else -> {
                        // Condition Met or Timeout
                        DebugLogger.log("SENSOR", "Condition Met: Tilt=${String.format("%.1f", tiltAngle)} Mov=${String.format("%.1f", movementMagnitude)} Timeout=$timedOut")
                        smartShutterClick()
                        successiveRemaining--

                        if (successiveRemaining > 0) {
                            handler.postDelayed({ triggerSuccessiveLoop() }, 1000)
                        } else {
                            finishBatch()
                        }
                    }
                }
            }
        }
        handler.post(checkCondition)

    } else {
        finishBatch()
    }
}

private fun finishBatch() {
    isCapturingBatch = false
    sensorManager?.unregisterListener(this)
    hapticHandler.removeCallbacks(hapticTickRunnable)
    val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
    val total = prefs.getInt("successive_count", 3)
    speak("Batch complete. ${total - 1} images.", true)
    hapticPulse(150, 50)
    DebugLogger.log("SENSOR", "Batch finished: Sensors released")
}

override fun onSensorChanged(event: SensorEvent?) {
    when (event?.sensor?.type) {
        Sensor.TYPE_LINEAR_ACCELERATION -> {
            movementMagnitude = Math.sqrt((event.values[0] * event.values[0] + event.values[1] * event.values[1] + event.values[2] * event.values[2]).toDouble()).toFloat()
        }
        Sensor.TYPE_GRAVITY -> {
            // Calculate tilt relative to the Z-axis (parallel to ground)
            val z = event.values[2]
            tiltAngle = Math.abs(Math.toDegrees(Math.acos((z / 9.81).coerceIn(-1.0, 1.0).toDouble()))).toFloat()
        }
    }
}

